// Share-surface assets, rendered from the same parting-gate art as icon.ts
// (regenerate: promo/capture/_assets.mjs). Embedded so the Worker serves its
// own faces — no third-party host.

function bytes(b64: string): Uint8Array {
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

// 180x180 of the ring-seal gate (same art as icon.ts) — reads as the NOMAD n.
// iOS rounds the corners itself.
const TOUCH_B64 =
  "";

// 1200x630 JPEG for og:image / twitter:image.
const OG_B64 =
  "";


const N512_B64 =
  "";
export const touchIconBytes = (): Uint8Array => bytes(TOUCH_B64);
export const iconN512Bytes = (): Uint8Array => bytes(N512_B64);
export const ogImageBytes = (): Uint8Array => bytes(OG_B64);


// The threshold's backdrops: rome's scene paintings (DALL-E, 2026-07-11) —
// the torch, the hound, the gate in rain, the weeper's arch, the black door,
// and the tide. Full-quality JPEGs, mostly darkness. Served at /door-bg/<name>.jpg
// (and /door-bg.jpg stays the torch, for anything that cached it).
const SCENE_TORCH_B64 =
  "";
const SCENE_HOUND_B64 =
  "";
const SCENE_RAIN_B64 =
  "";
const SCENE_ARCH_B64 =
  "";
const SCENE_DOOR_B64 =
  "";
const SCENE_TIDE_B64 =
  "";
const DOOR_SCENES: Record<string, string> = {
  torch: SCENE_TORCH_B64,
  hound: SCENE_HOUND_B64,
  rain: SCENE_RAIN_B64,
  arch: SCENE_ARCH_B64,
  door: SCENE_DOOR_B64,
  tide: SCENE_TIDE_B64,
};
export const doorSceneBytes = (name: string): Uint8Array | null =>
  DOOR_SCENES[name] ? bytes(DOOR_SCENES[name]) : null;
